const items = $input.all();
const imageParts = [];
let textContent = '';

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  // 仅在第一个 item 中提取文字描述
  if (i === 0) textContent = item.json?.['chatInput'] || '';

  const bin = item.binary || {};
  const binaryKeys = Object.keys(bin);

  for (const key of binaryKeys) {
    const b = bin[key];
    if (b) {
      const buffer = await this.helpers.getBinaryDataBuffer(i, key);
      const base64 = buffer.toString('base64');
      const mime = b.mimeType || 'image/jpeg';

      // 按照 Gemini 的 inline_data 格式打包
      imageParts.push({
        inline_data: {
          mime_type: mime,
          data: base64
        }
      });
    }
  }
}

// 最终只输出一个 item，包含所有图片和文字
return [{
  json: {
    text_11: textContent,
    gemini_images: imageParts // 这里包含了 1~N 张图
  }
}];

const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v));

const clean = (s) => {
  let t = toStr(s);
  t = t.replace(/```[\s\S]*?```/g, '');
  t = t.replace(/\*\*(.*?)\*\*/g, '$1');
  t = t.replace(/^\s*#{1,6}\s+/gm, '');
  t = t.replace(/["']/g, '');
  t = t.replace(/\n\s*\n\s*\n/g, '\n\n').trim();
  t = t.replace(/\r?\n/g, '').replace(/\\n/g, '');
  return t;
};

const extractText = (resp) => {
  const parts = resp?.candidates?.[0]?.content?.parts;
  if (Array.isArray(parts)) {
    const joined = parts.filter(p => p.text !== undefined).map(p => String(p.text)).join('\n');
    return clean(joined);
  }
  const fallback = toStr(resp?.text || resp?.content || resp?.message?.content);
  return clean(fallback);
};

const outputs = items.map((item) => {
  const response = item.json || {};
  const final_prompt = extractText(response);
  return { json: { final_prompt } };
});

return outputs.length ? outputs : [{ json: { final_prompt: '' } }];

const items = $input.all();

const toText = (obj, key, fallback) => {
  const v = obj?.[key];
  if (v == null) return fallback;
  if (Array.isArray(v)) return v.map(e => String(e).trim()).filter(Boolean).join('，') || fallback;
  const s = String(v).trim();
  return s || fallback;
};

const outputs = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const json = item.json || {};

  const market = toText(json, '目标市场', '未指定');
  const platform = toText(json, '目标平台', '未指定');
  const language = toText(json, '文案语言', '未指定');
  const aspect_ratio = toText(json, '图片比例', '1:1');
  const selling_points = toText(json, '核心卖点', '未提供');

  const integrated = `### 电商产品背景信息
- 目标市场: ${market}
- 目标平台: ${platform}
- 文案语言: ${language}
- 图片比例: ${aspect_ratio}
- 产品核心卖点: ${selling_points}

请基于以上信息，为该产品设计一个专业、吸引人的电商详情页设计风格概述。`.trim();

  const bin = item.binary || {};
  const keys = Object.keys(bin);
  const urls = [];

  for (const key of keys) {
    const buffer = await this.helpers.getBinaryDataBuffer(i, key);
    const base64 = Buffer.isBuffer(buffer) ? buffer.toString('base64') : Buffer.from(buffer).toString('base64');
    const meta = bin[key] || {};
    const mime = meta.mimeType || meta.mimetype || 'application/octet-stream';
    urls.push(`data:${mime};base64,${base64}`);
  }

  outputs.push({
    json: {
      integrated_info: integrated,
      image_url_full: urls.length === 1 ? urls[0] : '',
      image_urls_full: urls
    }
  });
}

return outputs.length ? outputs : [{ json: { integrated_info: '', image_url_full: '', image_urls_full: [] } }];

// Function 节点代码（终极修复版）
const images = $input.first().json.image_urls_full;
const integrated_info = $input.first().json.integrated_info;

if (!Array.isArray(images) || images.length === 0) {
  return { json: { error: "未提供任何图片" } };
}

const parts = [
  { text: typeof integrated_info === 'string' ? integrated_info : "请提供产品背景信息。" }
];

for (const base64Data of images) {
  if (typeof base64Data !== 'string') continue;
  const temp = base64Data.trim();
  if (!temp) continue;

  // 安全提取 MIME
  let mimeType = 'image/jpeg';
  const mimeMatch = temp.match(/^data:(image\/[^;]+);base64,/);
  if (mimeMatch) mimeType = mimeMatch[1];
  else if (temp.startsWith('image/')) {
    const simple = temp.split(';')[0];
    if (simple.startsWith('image/')) mimeType = simple;
  }

  // 安全提取 base64 数据
  let data = temp;
  if (temp.includes(',')) {
    data = temp.split(',')[1];
  }
  if (typeof data !== 'string' || data === '') continue;

  parts.push({
    inline_data: {
      mime_type: mimeType,
      data: data
    }
  });
}

// ✅ 构造纯净对象，确保所有值都是 string/number/boolean/null
const result = {
  contents: [{
    parts: parts.map(part => {
      // 确保每个 part 只含允许的字段
      if ('text' in part) {
        return { text: String(part.text) };
      } else if ('inline_data' in part) {
        return {
          inline_data: {
            mime_type: String(part.inline_data.mime_type),
            data: String(part.inline_data.data)
          }
        };
      }
      return part;
    })
  }]
};

// 最终验证
try {
  JSON.stringify(result);
} catch (e) {
  console.error("Serialization failed:", e);
  return { json: { error: "JSON invalid", detail: e.message } };
}

return { json: result }; // 👈 关键：只返回 { json: { ... } }

const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const getChatInput = () => {
  try {
    const n = $('Code in JavaScript4').first();
    return toStr(n?.json?.chatInput);
  } catch (_) {
    return '';
  }
};

const chatInput = getChatInput();
const base64_list = [];

for (let i = 0; i < items.length; i++) {
  const bin = items[i].binary || {};
  const keys = Object.keys(bin).filter(k =>
    k.startsWith('image') || k.startsWith('data') || k.startsWith('file') || k.startsWith('webp')
  );

  for (const key of keys) {
    const buf = await this.helpers.getBinaryDataBuffer(i, key);
    const b64 = Buffer.isBuffer(buf) ? buf.toString('base64') : Buffer.from(buf).toString('base64');
    if (b64) base64_list.push(b64);
  }
}

return [{
  json: {
    chatInput,
    base64_list
  }
}];

const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const collectPrompts = () => {
  const out = [];
  for (const it of items) {
    const j = it.json || {};
    const arr = j?.output?.text;
    if (Array.isArray(arr)) {
      for (const s of arr) {
        const t = toStr(s);
        if (t) out.push(t);
      }
    }
    const t1 = toStr(j.text);
    if (t1) out.push(t1);
    const t2 = toStr(j.content);
    if (t2) out.push(t2);
  }
  return Array.from(new Set(out));
};

const getChatFilesBinary = () => {
  try {
    const n = $('When chat message received').first();
    const bin = n?.binary || {};
    const keys = Object.keys(bin);
    return keys.map((key) => ({ key, data: bin[key] })).filter(x => x.data);
  } catch (_) {
    return [];
  }
};

const prompts = collectPrompts();
const files = getChatFilesBinary();

if (files.length) {
  return files.map(f => ({
    json: {
      prompts,
      fileName: f.data.fileName || f.key,
      mimeType: f.data.mimeType || ''
    },
    binary: { [f.key]: f.data }
  }));
}

return [{ json: { prompts } }];

// 当 Mode 为 "Run Once for All Items" 时，输入是一个名为 $input.all() 的数组
const allItems = $input.all();

// 处理每一项数据（通常 Chat Trigger 只有 1 个 Item）
return allItems.map(item => {
  const newBinary = {};

  // 获取当前 item 中所有的二进制键名 (例如: data0, data1)
  const binaryKeys = Object.keys(item.binary || {});

  // 按照你的要求，提取前 3 张并重命名
  binaryKeys.slice(0, 3).forEach((key, index) => {
    newBinary[`image_${index}`] = item.binary[key];
  });

  // 返回符合 n8n 规范的结构
  return {
    json: item.json,
    binary: newBinary
  };
});
